        },
        {
          "id": "points-rule-check-in",
          "role": "assertion",
          "binding": "/points/rules/check-in"
        },
        {
          "id": "points-rule-spend-ratio",
          "role": "assertion",
          "binding": "/points/rules/spend-ratio"
        },
        {
          "id": "points-history-list",
          "role": "list",
          "binding": "/points/history",
          "itemIdPattern": "points-history-{id}",
          "emptyStateId": "points-history-empty"
