          "id": "courses-add-button",
          "role": "action",
          "event": "open-add-course"
        },
        {
          "id": "courses-list",
          "role": "list",
          "binding": "/courses",
          "itemIdPattern": "course-card-{id}",
          "emptyStateId": "courses-empty-state"
        }
      ]
