          "id": "course-detail-back-button",
          "role": "action",
          "event": "navigate-back"
        },
        {
          "id": "course-detail-title",
          "role": "assertion",
          "binding": "/course/title"
        },
        {
          "id": "course-detail-time",
          "role": "assertion",
          "binding": "/course/time"
        },
        {
          "id": "course-detail-capacity",
          "role": "assertion",
          "binding": "/course/capacity"
        },
        {
          "id": "course-detail-material-list",
          "role": "list",
