    { "name": "open-filter-sheet", "context": {} },
    { "name": "open-add-member", "context": {} },
    { "name": "navigate-back", "context": {} },
    { "name": "open-edit-member", "context": { "memberId": "string" } },
    { "name": "open-redeem-sheet", "context": {} },
    { "name": "open-add-course", "context": {} },
    { "name": "open-book-course", "context": { "courseId": "string" } },
    { "name": "cancel-course-booking", "context": { "reservationId": "string" } },
    { "name": "open-add-material", "context": {} },
    { "name": "select-all-sleeping", "context": {} },
    { "name": "wake-selected-members", "context": { "memberIds": "string[]" } },
    { "name": "submit-check-in", "context": {} }
  ],
