    { "path": "/today/reservations/count", "type": "number" },
    { "path": "/points/activity", "type": "list" },
    { "path": "/sleeping/count", "type": "number" },
    { "path": "/members/search/query", "type": "string" },
    { "path": "/members", "type": "list" },
    { "path": "/member/name", "type": "string" },
    { "path": "/member/points", "type": "number" },
    { "path": "/member/craft-tags", "type": "list" },
    { "path": "/member/gallery", "type": "list" },
    { "path": "/member/points-history", "type": "list" },
    { "path": "/member/is-sleeping", "type": "boolean" },
    { "path": "/points/balance", "type": "number" },
    { "path": "/points/rules/check-in", "type": "number" },
    { "path": "/points/rules/spend-ratio", "type": "number" },
    { "path": "/points/history", "type": "list" },
    { "path": "/courses/selected-date", "type": "date" },
    { "path": "/courses", "type": "list" },
    { "path": "/course/title", "type": "string" },
    { "path": "/course/time", "type": "string" },
    { "path": "/course/capacity", "type": "string" },
    { "path": "/course/materials", "type": "list" },
    { "path": "/course/reservations", "type": "list" },
    { "path": "/inventory/search/query", "type": "string" },
    { "path": "/inventory", "type": "list" },
    { "path": "/inventory/low-stock-count", "type": "number" },
    { "path": "/sleeping/threshold-days", "type": "number" },
    { "path": "/sleeping-members", "type": "list" },
    { "path": "/check-in/selected-member", "type": "object" },
    { "path": "/check-in/type", "type": "string" },
    { "path": "/check-in/amount", "type": "number" },
    { "path": "/check-in/points", "type": "number" },
    { "path": "/check-in/selected-course", "type": "object" },
    { "path": "/profile/avatar", "type": "string" },
    { "path": "/profile/name", "type": "string" },
    { "path": "/settings/check-in-points", "type": "number" },
    { "path": "/settings/spend-ratio", "type": "number" },
    { "path": "/settings/sleeping-threshold", "type": "number" },
    { "path": "/settings/notifications-enabled", "type": "boolean" }
  ],
  "testTargets": [
    { "id": "home-quick-check-in-button", "action": "tap" },
    { "id": "members-add-button", "action": "tap" },
    { "id": "members-search-input", "action": "input" },
    { "id": "member-card-{id}", "action": "tap" },
    { "id": "course-detail-book-button", "action": "tap" },
    { "id": "check-in-submit-button", "action": "tap" },
    { "id": "sleeping-members-wake-button", "action": "tap" },
    { "id": "inventory-item-{id}", "action": "tap" }
  ]
}

